ew_load_form'] = 'request_injection/form';		$component['load_js'][] = 'request_injection/view';		$component['load_js'][] = 'request_injection/form';				$component['page_title'] = "Request Warehouse 2";				$dashboard_table = array();				$nav_button = array();		$nav_button[] = array('method_id' => 50017,'title' => 'Add', 'icon' => 'fa fa-plus', 'load' => 'request_injection/function_add');		$nav_button[] = array('method_id' => 50018,'title' => 'Edit', 'icon' => 'fa fa-pencil', 'load' => 'request_injection/function_edit');		$nav_button[] = array('method_id' => 50020,'title' => 'Approve', 'icon' => 'fa fa-pencil', 'load' => 'request_injection/function_approve');		$nav_button[] = array('method_id' => 50019,'title' => 'Delete', 'icon' => 'fa fa-trash-o', 'load' => 'request_injection/function_delete');		$nav_button[] = array('method_id' => 50021,'title' => 'Cancel Approve', 'icon' => 'fa fa-cross', 'load' => 'request_injection/function_cancel_approve');		$nav_button[] = array('method_id' => 50051,'title' => 'Print', 'icon' => 'fa fa-print', 'load' => 'request_injection/function_print_request');				$field = $this->request_injection_table();		$field_detail = $this->request_injection_detail_table();		$field_detail_supply = $this->request_injection_detail_supply_table();		$field_transfer_item = $this->request_injection_transfer_item_table();		$field_supply_item = $this->request_injection_supply_item_table();		$field_cek_stock = $this->cek_stock_table();				$dashboard_table['nav_button'] = $nav_button;		$dashboard_table['field'] = $field;		$dashboard_table['field_detail'] = $field_detail;		//$dashboard_table['field_detail_supply'] = $field_detail_supply;		$dashboard_table['field_detail_loaddata'] = 'loaddata_detail';		//$dashboard_table['field_detail_supply_loaddata'] = 'loaddata_detail_supply';		//$dashboard_table['field_transfer_item'] = $field_transfer_item;		//$dashboard_table['field_transfer_item_loaddata'] = 'loaddata_transfer_item';		//$dashboard_table['field_supply_item'] = $field_supply_item;		//$dashboard_table['field_supply_item_loaddata'] = 'loaddata_supply_item';				//$dashboard_table['field_cek_stock'] = $field_cek_stock;		//$dashboard_table['field_cek_stock_loaddata'] = 'loaddata_cek_stock';		//$field = $this->mutasi_bahan_baku_table();		//$dashboard_table['field'] = $field;				$component['dashboard_table'] = $dashboard_table;				$this->authentication->ajaxlayout($component);	}		function loaddata() {		$this->authentication->plainlayout();				$view = 'view_request_injection';		$field = $this->request_injection_table();				$return = array();		$return['valid'] = false;		$return['message'] = "Internal Server Error"; 		$loaddata = $this->ecc_library->get_field_data($view,$field);					echo $loaddata;	}				function loaddata_cek_stock(){				$field = $this->cek_stock_table();				$date_start = isset($_REQUEST['date_start']) ?  $_REQUEST['date_start'] : '';		$date_end = isset($_REQUEST['date_end']) ? $_REQUEST['date_end'] : '';		$request_id = isset($_REQUEST['request_id']) ? is_numeric($_REQUEST['request_id']) ? $_REQUEST['request_id']  : -1 : -1;		$print = isset($_REQUEST['print']) ? $_REQUEST['print'] : 0;		$format = isset($_REQUEST['format']) ? $_REQUEST['format'] : 'xlsx';		$page = isset($_POST['page'])?$_POST['page']:1; // get the requested page         $rows = isset($_POST['rows'])?$_POST['rows']:10; // get how many rows we want to have into the grid         $sidx = isset($_POST['sidx'])?$_POST['sidx']:'r1'; // get index row - i.e. user click to sort         $sord = isset($_POST['sord'])?$_POST['sord']:'0'; // get the direction 		$search = isset($_REQUEST['_search'])?$_REQUEST['_search']:false; 		$filterRules =  isset($_POST['filters'])?$_POST['filters']:false;						$limit =  $rows;		$offset =  $rows * ($page - 1);				$order = isset($_REQUEST['order']) ? $_REQUEST['order'] : array();				if($sord == 'asc'){			$sord = 1;		} else {			$sord = 2;		}				$sort =	$sidx. '='.$sord;							if(strlen(trim($date_start)) == 0 ){			$date_start = '1900-01-01';		}				if(strlen(trim($date_end)) == 0 ){			$date_end = '9999-12-31';		}				$return = array();		$return['valid'] = false;		$return['message'] = "Internal Server Error";											$sp = "dbo.sp_cek_stock_report_assets";				if($print == 1){			$this->rpc_service->setSP(array("sp"=> $sp,"mode"=> $print == 1 ? "2" : "1","debug"=>"1"));		} else {			$this->rpc_service->setSP($sp);		}				$this->rpc_service->addField('date_start',$date_start);		$this->rpc_service->addField('date_end',$date_end);		$this->rpc_service->addField('request_id',$request_id);		$this->rpc_service->addField('format',$format);		$this->rpc_service->addField('temp_folder',sys_get_temp_dir());		$this->rpc_service->addField('sort',$sort);		$this->rpc_service->addField('limit',$limit);		$this->rpc_service->addField('offset',$offset);						$this->rpc_service->setWhere($search,$filterRules,$field);				if($print == 1){						$result = $this->rpc_service->resultPrint2();			echo json_encode($result);		} else {			$this->authentication->plainlayout();									$result = $this->rpc_service->resultJSON_pop();				//var_dump($result);			$data_result = json_decode($result['data'],true);		//	var_dump($result);die();						if(isset($data_result['detail']['result_count'])){				$records = $data_result['detail']['result_count'];				$total = ceil($data_result['detail']['result_count'] / $limit);			} else {				$records = 0;				$total = 0;			}						$responce = new stdclass();			$responce->page = $page;			$responce->records = $records;			$responce->total = $total;			$i=0; 			if($data_result){				if(isset($data_result['xrow'])){					foreach($data_result['xrow'] as $key=>$value){						foreach ($value as $k => $v) {							$responce->rows[$i][$k] = $v;						} 						$i++;					}				}			}					echo json_encode($responce);		}	}			function approve(){		$this->authentication->plainlayout();		$parameter = array();		$return = array();						$request_id = isset($_POST['request_id']) ? $_POST['request_id'] : false;				$user_id = $this->session->userdata('user_id');				$result = array();		$return['valid'] = false;		$return['status_code'] = 501;		$return['message'] = "Internal Server Error";				if(count($_POST) > 0){						if($request_id){				$this->rpc_service->setSP("dbo.sp_request_injection_approve");				$this->rpc_service->addField('request_id',$request_id);			}								$result = $this->rpc_service->resultJSON();			// print_r($result);						$data = array();			if(isset($result)){				if(isset($result['valid'])){					if($result['valid']){						if(isset($result['data'])){							$return['valid'] = $result['valid'];							$return['status_code'] = $result['no'];							$return['message'] = $result['des'];						}					} else {						$return['status_code'] = $result['no'];						$return['message'] = $result['des'];					}				}			}					} else {			$return['valid'] = false;			$return['message'] = "Session expired";		}				echo json_encode($return);	}		function cancel_approve(){		$this->authentication->plainlayout();		$parameter = array();		$return = array();						$request_id = isset($_POST['request_id']) ? $_POST['request_id'] : false;				$user_id = $this->session->userdata('user_id');				$result = array();		$return['valid'] = false;		$return['status_code'] = 501;		$return['message'] = "Internal Server Error";				if(count($_POST) > 0){						if($request_id){				$this->rpc_service_portal->setSP("dbo.sp_request_injection_cancel_approve");				$this->rpc_service_portal->addField('request_id',$request_id);			}								$result = $this->rpc_service_portal->resultJSON();			// print_r($result);						$data = array();			if(isset($result)){				if(isset($result['valid'])){					if($result['valid']){						if(isset($result['data'])){							$return['valid'] = $result['valid'];							$return['s